package main

import "fmt"

func max(a, b int) int {
    if a > b {
        return a
    }
    return b
}

func swap(x, y string) (string, string) {
    return y, x
}

func main() {
    fmt.Println("Max:", max(10, 20))
    a, b := swap("first", "second")
    fmt.Println("Swap:", a, b)
}

lessons.theory:
## Structs over Classes
Go doesn't have classes. It has `structs` (custom data types) and `interfaces` (behavior contracts).

```go
type Animal interface {
    Speak() string
}

type Dog struct {}
func (d Dog) Speak() string { return "Woof" }
```

