package main

import "fmt"

func main() {
    // Create a string channel
    messages := make(chan string)

    go func() {
        messages <- "Ping"
        messages <- "Pong"
        messages <- "Done"
    }()

    msg1 := <-messages
    msg2 := <-messages
    msg3 := <-messages

    fmt.Println(msg1, msg2, msg3)
